 6→export async function signUp(formData: FormData) {
 7→  const supabase = await createClient();
 8→
 9→  const email = formData.get("email") as string;
10→  const password = formData.get("password") as string;
11→  const username = formData.get("username") as string;
12→
13→  const { error } = await supabase.auth.signUp({
14→    email,
15→    password,
16→    options: {
17→      data: { username },
18→    },
19→  });
20→
21→  if (error) {
22→    return { error: error.message };
23→  }
24→
25→  redirect("/");
26→}
